class BlockDecomposition {
private:
	// --------------------------------------
	// [通用] 变量
	// --------------------------------------
	int n;                  // 数组总长度
	int block_size;         // 块的大小 S
	int num_blocks;         // 块的总数
	vector<int> a;          // 原始数组 (下标 1 到 n)
	vector<int> id;         // id[i] 表示原数组第 i 个元素属于哪个块
	vector<int> L, R;       // L[b], R[b] 分别表示第 b 个块的左右端点下标

	// --------------------------------------
	// [具体情况具体分析] 块内维护的附加信息与标记
	// 本题需要：加法懒标记 + 块内排序数组
	// --------------------------------------
	vector<vector<int>> pos;       // 每个值 i 出现的所有下标 j
	vector<vector<int>> cnt;       // 前 i 个块 val 出现的个数
	vector<vector<int>> mode;      // 第 i 个块到第 j 个块的最小众数
	vector<int> tmp_cnt;           // 临时记录 val 出现的次数

public:
	// --------------------------------------
	// [通用] 构造函数，初始化
	// --------------------------------------
	BlockDecomposition(const vector<int>& input) {
		n = input.size() - 1; // 默认 input 下标从 1 开始
		a = input;
		block_size = max(1, (int)sqrt(n));
		num_blocks = (n - 1) / block_size + 1;

		id.resize(n + 1);
		L.resize(num_blocks + 1, 0);
		R.resize(num_blocks + 1, 0);

		// [具体情况具体分析] 对具体分析的变量初始化空间
		pos.resize(n + 1);
		tmp_cnt.assign(n + 1, 0);
		cnt = Vec2<int>(num_blocks + 1, n + 1);
		mode = Vec2<int>(num_blocks + 1, num_blocks + 1);

		// 计算每个元素的块归属 和 每个块的左右边界
		fa(i, 1, n) {
			id[i] = (i - 1) / block_size + 1;
			if (L[id[i]] == 0) L[id[i]] = i;
			R[id[i]] = i;

			// 初始化 pos, cnt
			pos[a[i]].pb(i);
			cnt[id[i]][a[i]]++;
		}

		// 初始化前缀和
		fa(i, 1, num_blocks)fa(j, 1, n)cnt[i][j] += cnt[i - 1][j];

		// [具体情况具体分析] 初始预处理
		fa(i, 1, num_blocks)fa(j, i, num_blocks) {
			int ans = INF, anscnt = 0;
			if (i == j) {
				// 在同一个块内，暴力判断
				var tmp_cnt = ccHashMap<int, int, MT::custom_hash>();
				fa(k, L[j], R[j]) {
					tmp_cnt[a[k]]++;
					if (anscnt < tmp_cnt[a[k]]) {
						anscnt = tmp_cnt[a[k]];
						ans = a[k];
					}
					else if (anscnt == tmp_cnt[a[k]] and ans > a[k]) {
						ans = a[k];
					}
				}
				fa(k, L[j], R[j])tmp_cnt[a[k]]--;
			}
			else {
				// 不在同一个块内，前缀和算整块区间每个数出现的个数
				// mode[i][j] 的值域选择为：{ mode[i][j - 1]，第 j 个块中的数 }
				var tmp = vector<int>{ mode[i][j - 1] };
				fa(k, L[j], R[j])tmp.pb(a[k]);
				for (int x : tmp) {
					int tmp_cnt = cnt[j][x] - cnt[i - 1][x];
					if (anscnt < tmp_cnt) {
						anscnt = tmp_cnt;
						ans = x;
					}
					else if (anscnt == tmp_cnt and ans > x) {
						ans = x;
					}
				}
			}
			mode[i][j] = ans;
		}
	}

	// --------------------------------------
	// [具体情况具体分析] 区间查询操作，怎么查询具体情况具体分析
	// 逻辑骨架是通用的：分同块、左散块、右散块、中间整块
	// --------------------------------------
	int query(int l, int r) {
		int bl = id[l], br = id[r];
		int ans = INF, anscnt = 0;
		if (bl == br) {
			// 在同一个块内，暴力判断
			fa(k, l, r) {
				tmp_cnt[a[k]]++;
				if (anscnt < tmp_cnt[a[k]]) {
					anscnt = tmp_cnt[a[k]];
					ans = a[k];
				}
				else if (anscnt == tmp_cnt[a[k]] and ans > a[k]) {
					ans = a[k];
				}
			}
			fa(k, l, r)tmp_cnt[a[k]]--;
		}
		else {
			// 不在同一个块内，前缀和算整块区间每个数出现的个数，散块暴力计数
			// query(l, r) 的值域选择为：{ mode[bl + 1][br - 1]，第 bl 个块中的数，第 br 个块中的数 }
			var tmp = vector<int>{ mode[bl + 1][br - 1] };
			fa(k, l, L[bl + 1] - 1)tmp.pb(a[k]), tmp_cnt[a[k]]++;
			fa(k, R[br - 1] + 1, r)tmp.pb(a[k]), tmp_cnt[a[k]]++;

			for (int x : tmp) {
				int real_cnt = tmp_cnt[x] + cnt[br - 1][x] - cnt[bl][x];
				if (anscnt < real_cnt) {
					anscnt = real_cnt;
					ans = x;
				}
				else if (anscnt == real_cnt and ans > x) {
					ans = x;
				}
			}

			fa(k, l, L[bl + 1] - 1)tmp_cnt[a[k]]--;
			fa(k, R[br - 1] + 1, r)tmp_cnt[a[k]]--;
		}
		return ans;
	}
};

void solve(int CASE)
{
	int n, q; cin >> n >> q;
	var a = vector<int>(n + 1);
	var b = vector<int>();
	fa(i, 1, n)cin >> a[i], b.pb(a[i]);
	sort(all(b));
	b.erase(unique(all(b)), b.end());
	var find = [&](int value)->int {
		return upper_bound(all(b), value) - b.begin();
		};
	fa(i, 1, n)a[i] = find(a[i]);

	var bd = BlockDecomposition(a);
	int ans = 0;
	fa(i, 1, q) {
		int l, r; cin >> l >> r;
		l = (l + ans - 1) % n + 1, r = (r + ans - 1) % n + 1;
		if (l > r)swap(l, r);
		ans = b[bd.query(l, r) - 1];
		cout << ans << endl;
	}
	return;
}
